def check_alert_conditions(data: dict, conditions: list[dict]) -> bool:
    for condition in conditions:
        metric = condition.get('metric')
        operator = condition.get('operator')
        value_to_compare = condition.get('value')

        if metric not in data:
            continue

        current_value = data[metric]

        if operator == 'gt':
            if current_value > value_to_compare:
                return True
        elif operator == 'lt':
            if current_value < value_to_compare:
                return True
        elif operator == 'ge':
            if current_value >= value_to_compare:
                return True
        elif operator == 'le':
            if current_value <= value_to_compare:
                return True
        elif operator == 'eq':
            if current_value == value_to_compare:
                return True
        elif operator == 'ne':
            if current_value != value_to_compare:
                return True
        elif operator == 'in':
            if isinstance(value_to_compare, (list, tuple, set)) and current_value in value_to_compare:
                return True
        elif operator == 'not_in':
            if isinstance(value_to_compare, (list, tuple, set)) and current_value not in value_to_compare:
                return True
    return False
